#include<cstdio>
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline char Get(){char c;do c=getchar();while(c!='Q'&&c!='A');return c;}
typedef long long LL;inline void print(const LL&p){if(p>9)print(p/10);putchar(p%10+'0');}
inline void pt(const LL&p,const char&ch='\n'){print(p<0?putchar('-'),-p:p);putchar(ch);}
const int N=1e5+10;
namespace LCT
{
	int ch[N][2],fa[N],sz[N],sz2[N];bool tg[N];
	inline void Swap(int&x,int&y){int tmp=x;x=y;y=tmp;}
	inline void update(int x){if(x)sz[x]=sz[ch[x][0]]+sz[ch[x][1]]+sz2[x]+1;}
	inline void Rev(int x){Swap(ch[x][0],ch[x][1]);tg[x]^=1;}
	inline void pushdown(int x){if(tg[x]){Rev(ch[x][0]);Rev(ch[x][1]);tg[x]=false;}}
	inline bool nrt(const int &x){return ch[fa[x]][0]==x||ch[fa[x]][1]==x;}
	inline void rotate(int x)
	{
		int y=fa[x],z=fa[y];bool k=ch[y][1]==x;
		if(nrt(y))ch[z][ch[z][1]==y]=x;int w=ch[x][!k];ch[ch[x][!k]=y][k]=w;
		if(w)fa[w]=y;fa[fa[y]=x]=z;update(y);update(x);update(z);
	}
	inline void pushall(int x){if(nrt(x))pushall(fa[x]);pushdown(x);}
	inline void splay(int x)
	{
		pushall(x);const int &y=fa[x];
		while(nrt(x))nrt(y)?rotate((ch[fa[y]][0]==y)^(ch[y][0]==x)?x:y):void(),rotate(x);
	}
	inline void access(int x){for(int y=0;x;x=fa[y=x])splay(x),sz2[x]+=sz[ch[x][1]]-sz[y],ch[x][1]=y,update(x);}
	inline void makeRt(int x){access(x);splay(x);Rev(x);}
	inline void split(int x,int y){makeRt(x);access(y);splay(y);}
	inline void lnk(int x,int y){makeRt(x);makeRt(y);fa[x]=y;sz2[y]+=sz[x];}
	inline void qry(int x,int y)
	{
		makeRt(x);access(y);splay(y);ch[y][0]=fa[x]=0;update(x);
		makeRt(x);makeRt(y);pt(1ll*sz[x]*sz[y]);lnk(x,y);
	}
}
using namespace LCT;
int main()
{
	int n=read(),m=read();while(m--)switch(Get())
	{
		case 'A': lnk(read(),read());break;
		case 'Q': qry(read(),read());break;
	}
}
